                .map(str::to_string)
        };
    let downstream_dispatch_result_path = packet
        .get("downstream_dispatch_result_path")
        .and_then(serde_json::Value::as_str)
        .map(str::to_string);
    if let Some(error) = resume_packet_ready_blocker_parity_error(

